#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-06-03

# ============================================================================
# Tool-Call Signature Conformance Tests
# ============================================================================
# Validates that tool-call EXAMPLES authored in skill .md files use parameter
# names that exist in the live Claude Code tool schemas. Skill examples drift
# from the schemas across CC versions; an agent that copies a stale example
# calls the tool with non-existent params and fails at runtime.
#
# This generalizes test-askuserquestion-schema.sh (one tool) to the highest-
# drift built-in tools. It was prompted by orchestkit#2176, where a 61-skill
# audit found SendMessage(recipient:/type:/broadcast) and
# PushNotification(title:/body:) examples across 5 skills — all schema-invalid.
#
# What it checks (conservative, low-false-positive):
#   - ERROR on any top-level parameter name NOT in the tool's allowed set.
#     Known-legacy names get a "did you mean" hint.
#   - It does NOT require all params (doc snippets are often partial), so it
#     won't flag an illustrative `PushNotification(message=...)`. Only WRONG
#     names are errors.
#
# Registry (params per live CC schema, 2026-06-03):
#   SendMessage      → {to, message, summary}      (legacy: recipient, content, type)
#   PushNotification → {message, status}           (legacy: title, body)
#
# To extend: add a tool to TOOLS below with its allowed-param set.
#
# Usage: ./test-tool-call-signatures.sh [--verbose]
# Exit codes: 0 = all pass, 1 = violations found
# ============================================================================

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="${CLAUDE_PROJECT_DIR:-$(cd "$SCRIPT_DIR/../../.." && pwd)}"
SKILLS_DIR="$PROJECT_ROOT/src/skills"
VERBOSE="${1:-}"

if [[ -t 1 ]]; then
    RED='\033[0;31m'; GREEN='\033[0;32m'; CYAN='\033[0;36m'; NC='\033[0m'
else
    RED=''; GREEN=''; CYAN=''; NC=''
fi

echo -e "${CYAN}Tool-call signature conformance${NC} — scanning $SKILLS_DIR"

VERBOSE="$VERBOSE" python3 - "$SKILLS_DIR" <<'PYEOF'
import os, re, sys

skills_dir = sys.argv[1]
verbose = os.environ.get("VERBOSE", "") in ("--verbose", "-v")

# Allowed top-level param names per live CC tool schema, plus known-legacy
# names that drifted in (mapped to the correct form for the hint).
TOOLS = {
    "SendMessage": {
        "allowed": {"to", "message", "summary"},
        "legacy": {
            "recipient": "to", "content": "message", "type": "message (nest type inside the message object)",
            "recipients": "to",
        },
    },
    "PushNotification": {
        "allowed": {"message", "status"},
        "legacy": {"title": "message", "body": "message", "text": "message"},
    },
}

violations = []   # "file:line  message"
calls_checked = 0


def scan_string_aware(text, start, open_ch, close_ch):
    """Index of close_ch matching open_ch at `start`, ignoring quoted strings."""
    depth = 0
    i = start
    in_str = False
    quote = ""
    while i < len(text):
        c = text[i]
        if in_str:
            if c == "\\":
                i += 2
                continue
            if c == quote:
                in_str = False
        else:
            if c in ("\"", "'"):
                in_str = True
                quote = c
            elif c == open_ch:
                depth += 1
            elif c == close_ch:
                depth -= 1
                if depth == 0:
                    return i
        i += 1
    return -1


def top_level_param_names(body):
    """Top-level kwarg names in a call body — identifiers immediately followed
    by ':' or a single '=' at depth 0, string-aware. Does not descend into
    nested objects/arrays/calls (so a `message: {type: ...}` value is not
    mistaken for a `type` param)."""
    names = []
    i = 0
    depth = 0
    in_str = False
    quote = ""
    n = len(body)
    while i < n:
        c = body[i]
        if in_str:
            if c == "\\":
                i += 2
                continue
            if c == quote:
                in_str = False
            i += 1
            continue
        if c in ("\"", "'"):
            in_str = True
            quote = c
            i += 1
            continue
        if c in "{[(":
            depth += 1
            i += 1
            continue
        if c in "}])":
            depth -= 1
            i += 1
            continue
        if depth == 0 and (c.isalpha() or c == "_"):
            j = i
            while j < n and (body[j].isalnum() or body[j] == "_"):
                j += 1
            tok = body[i:j]
            k = j
            while k < n and body[k] in " \t\n":
                k += 1
            if k < n and (
                body[k] == ":"
                or (body[k] == "=" and (k + 1 >= n or body[k + 1] != "="))
            ):
                # exclude '==' '!=' '>=' '<=' (k-1 handled by single-'=' rule above)
                names.append(tok)
            i = j
            continue
        i += 1
    return names


def line_of(text, idx):
    return text[:idx].count("\n") + 1


for root, _dirs, fnames in os.walk(skills_dir):
    for fn in fnames:
        if not fn.endswith(".md"):
            continue
        path = os.path.join(root, fn)
        rel = os.path.relpath(path, os.path.dirname(skills_dir))
        text = open(path, encoding="utf-8").read()

        for tool, spec in TOOLS.items():
            allowed = spec["allowed"]
            legacy = spec["legacy"]
            for m in re.finditer(r"\b" + re.escape(tool) + r"\s*\(", text):
                paren = text.index("(", m.start())
                close = scan_string_aware(text, paren, "(", ")")
                if close == -1:
                    continue
                body = text[paren + 1:close]
                names = top_level_param_names(body)
                if not names:
                    continue  # positional / no kwargs — nothing to validate
                calls_checked += 1
                ln = line_of(text, m.start())
                for nm in names:
                    if nm in allowed:
                        continue
                    if nm in legacy:
                        violations.append(
                            f"{rel}:{ln}  {tool}(): `{nm}` is not a valid param — "
                            f"use `{legacy[nm]}` (live schema: {{{', '.join(sorted(allowed))}}})"
                        )
                    else:
                        violations.append(
                            f"{rel}:{ln}  {tool}(): unknown param `{nm}` "
                            f"(live schema allows: {{{', '.join(sorted(allowed))}}})"
                        )

print(f"  Tools checked: {', '.join(sorted(TOOLS))}")
print(f"  Calls validated: {calls_checked}")
if violations:
    print(f"\n  \033[0;31m{len(violations)} signature violation(s):\033[0m")
    for v in sorted(set(violations)):
        print(f"    - {v}")
    print("\n  Fix: update the example to the live tool schema. If a CC schema")
    print("  genuinely changed, update the registry in this test.")
    sys.exit(1)
print("  \033[0;32mAll tool-call examples conform to live schemas\033[0m")
PYEOF
